function buildLocations(kind, spotName, city) {
  if (kind === 'citywalk') {
    const detail = getCitywalkRouteDetail(city);
    if (detail) return buildCitywalkDetailLocations(city, detail);
  }

  const prefixSource = kind === 'citywalk' ? city : spotName;
  const prefix = String(prefixSource || '').replace(/\s+/g, '').slice(0, 8);
  return (spotLocationTemplates[kind] || spotLocationTemplates.city).map(([name, desc, time, tip, type]) => ({
    name: prefix ? `${prefix}${name}` : name,
    desc,
    time,
    tip,
    type,
    ...(locationGuidePresets[name] || {})
  }));
}

function makeSpotFromBlueprint(item, index) {
  const [name, city, location, lat, lng, score, badge, archiveNo, bestTime, summary, image, label, prompt, palette, kind, extraTags = []] = item;
  return {
    id: 101 + index,
    name,
    city,
    province: getProvinceForCity(city),
    location,
    lat,
    lng,
    score,
    badge,
    archiveNo,
    bestTime,
    summary,
    aiExampleImage: image,
    aiExampleLabel: label,
    aiExamplePrompt: prompt,
    palette,
    tags: [city, badge, kind].concat(extraTags),
    themeTags: [badge].concat(extraTags).slice(0, 4),
    locations: buildLocations(kind, name, city),
    tips: [
      '热门时段人流较多，建议提前 20 分钟到场观察光线和人流。',
      '拍摄时不要占用通道或危险边缘，先保证通行和安全。',
      '优先选择顺光、侧光或反光面补脸，中午强光可找阴影边缘。'
    ],
    composition: [
      '先确定地标主体，再把人物放在三分线或画面边缘。',
      '保留天空、水面、街道或墙面留白，让画面更干净。',
      '用栏杆、桥线、街道、岸线或台阶制造视觉引导。'
    ]
  };
}

