const cityProvinceMap = {};
provinceCityGroups.forEach(([province, cities]) => {
  cities.forEach((city) => {
    cityProvinceMap[city] = province;
  });
});

function getProvinceForCity(city) {
  return cityProvinceMap[city] || city;
}

