function getCitywalkRouteBase(city) {
  if (citywalkRouteMap[city]) return citywalkRouteMap[city];
  const province = getProvinceForCity(city);
  if (['浙江', '江苏', '安徽', '福建', '江西'].includes(province)) {
    return `${city}老街口 - 历史街巷 - 河岸/湖边步道 - 地标广场`;
  }
  if (['广东', '广西', '海南', '山东'].includes(province)) {
    return `${city}老街口 - 生活市集 - 海边/江边步道 - 日落地标`;
  }
  if (['四川', '贵州', '云南', '西藏', '甘肃', '青海', '新疆', '内蒙古'].includes(province)) {
    return `${city}游客中心街口 - 本地街巷 - 公园/河谷步道 - 城市观景位`;
  }
  if (['山西', '河南', '陕西', '河北'].includes(province)) {
    return `${city}古城门/老街口 - 历史街巷 - 本地小吃街 - 城墙/广场收尾`;
  }
  return `${city}街区入口 - 本地生活街巷 - 河岸/公园步道 - 地标广场收尾`;
}

function getCitywalkRoute(city) {
  const detail = getCitywalkRouteDetail(city);
  const midStops = detail.stops.map(([name]) => name).slice(1, -1).join(' → ');
  return `${detail.start}${midStops ? ` → ${midStops}` : ''} → ${detail.end}（${detail.distance}，${detail.duration}）`;
}

function getCitywalkSummary(city) {
  const detail = getCitywalkRouteDetail(city);
  const midStops = detail.stops
    .slice(1, -1)
    .map(([name, role]) => `${name}（${role}）`)
    .join('、');

  return `${city}Citywalk步行线从${detail.start}开始，到${detail.end}收尾，${detail.distance}，建议预留${detail.duration}。中途重点经过${midStops}，每一站都标明了店铺/街区用途和拍摄重点。`;
}

