function getCitywalkRouteDetail(city) {
  return citywalkRouteDetails[city] || buildSyntheticCitywalkRouteDetail(city);
}

function splitCitywalkStops(routeText) {
  return String(routeText || '')
    .split(/\s*[-→]\s*/g)
    .map((item) => item.trim())
    .filter(Boolean);
}

function getSyntheticDistance(stopCount) {
  if (stopCount <= 3) return '约 2.5 公里';
  if (stopCount === 4) return '约 3 公里';
  return '约 3.5 公里';
}

function getSyntheticDuration(stopCount) {
  if (stopCount <= 3) return '2-2.5 小时';
  if (stopCount === 4) return '2.5-3 小时';
  return '3-4 小时';
}

function inferCitywalkRole(name, index, total) {
  if (index === 0) return '起点街口';
  if (index === total - 1) return '终点地标';

  if (/市集|市场|巴扎|夜市|小吃|美食|步行街|商圈|商业|广场|天地|街区/.test(name)) return '市集/商业街区';
  if (/老街|古街|古城|古镇|历史|巷|坊|弄|胡同|骑楼|城墙|城门|街口/.test(name)) return '历史街巷';
  if (/公园|湖|河|江|海|湾|岸|码头|滨|桥|水/.test(name)) return '公园/水岸';
  if (/书店|书院|博物馆|美术馆|剧场|艺术|文化|文创|创意|展|园区/.test(name)) return '文化/文创空间';
  if (/寺|庙|宫|塔|楼|阁|祠|故居|旧址|公馆/.test(name)) return '历史地标';
  if (/路|街|道/.test(name)) return '街区慢走段';
  return '城市观察点';
}

function describeSyntheticStop(name, role, city) {
  const descriptions = {
    '起点街口': `${name}适合作为${city}Citywalk开场，先拍路牌、入口和第一段行走方向。`,
    '终点地标': `${name}适合作为路线终点，补一张完整环境照或人小景大的收尾封面。`,
    '市集/商业街区': `${name}适合拍店招、人流、摊位、橱窗和手持小吃，体现本地生活热度。`,
    '历史街巷': `${name}适合拍老建筑、门头、巷道纵深和路牌，画面更有城市记忆。`,
    '公园/水岸': `${name}适合拍水面留白、树影、栏杆侧身和日落前的散步氛围。`,
    '文化/文创空间': `${name}适合拍展览海报、书店门头、墙面装置和安静半身照。`,
    '历史地标': `${name}适合拍地标外立面、牌匾、墙面纹理和文化感人像。`,
    '街区慢走段': `${name}适合边走边拍，重点找转角、树影、店招和道路延伸线。`,
    '城市观察点': `${name}适合作为中途观察点，拍路牌、街角、人物行走和环境细节。`
  };

  return descriptions[role] || descriptions['城市观察点'];
}

function buildSyntheticCitywalkRouteDetail(city) {
  const stops = splitCitywalkStops(getCitywalkRouteBase(city));
  const normalizedStops = stops.length >= 2 ? stops : [`${city}街区入口`, `${city}本地街巷`, `${city}地标广场`];

  return {
    start: normalizedStops[0],
    end: normalizedStops[normalizedStops.length - 1],
    distance: getSyntheticDistance(normalizedStops.length),
    duration: getSyntheticDuration(normalizedStops.length),
    stops: normalizedStops.map((name, index) => {
      const role = inferCitywalkRole(name, index, normalizedStops.length);
      return [name, role, describeSyntheticStop(name, role, city)];
    })
  };
}

function buildCitywalkDetailLocations(city, detail) {
  return detail.stops.map(([name, role, desc], index) => {
    const isFirst = index === 0;
    const isLast = index === detail.stops.length - 1;
    const type = isFirst ? '起点' : (isLast ? '终点' : role);
    const time = isFirst ? '上午/下午柔光' : (isLast ? '日落前/蓝调时刻' : '下午侧光');
    const guide = isFirst
      ? locationGuidePresets.起点街口集合位
      : (isLast ? locationGuidePresets.收尾地标打卡位 : locationGuidePresets.中段街巷慢走位);

    return {
      name: `${index + 1}. ${name}`,
      address: `${city}${name}`,
      mapKeyword: `${city} ${name}`,
      desc: `${role}：${desc}`,
      time,
      tip: isFirst
        ? `从${detail.start}开始，先拍带路牌或入口的开场照。`
        : (isLast ? `终点到${detail.end}，补一张完整收尾照。` : '中途只选一个最清楚的门头、路牌或橱窗，不要每家店都停太久。'),
      type,
      angle: guide.angle,
      lens: guide.lens,
      direction: guide.direction,
      example: guide.example,
      result: guide.result,
      stand: guide.stand,
      action: guide.action,
      visual: guide.visual,
      pose: guide.pose,
      cue: role,
      diagramNote: guide.diagramNote
    };
  });
}

