function getCityKind(city, province, index) {
  if (cityKindHints[city]) return cityKindHints[city];
  if (['海南', '广西', '浙江', '福建', '山东', '青海'].includes(province)) return index % 2 === 0 ? 'water' : 'oldtown';
  if (['四川', '贵州', '云南', '西藏', '甘肃', '新疆', '内蒙古'].includes(province)) return index % 2 === 0 ? 'mountain' : 'oldtown';
  if (['山西', '河南', '陕西', '河北'].includes(province)) return index % 2 === 0 ? 'palace' : 'oldtown';
  return index % 3 === 0 ? 'city' : (index % 3 === 1 ? 'oldtown' : 'water');
}

