function pickRouteImage(province, city, kind, globalIndex, routeProfile) {
  const cityImages = cityRouteImageOverrides[city];
  if (cityImages && cityImages[routeProfile.suffix]) return cityImages[routeProfile.suffix];

  const pool = routeKindImagePools[kind] || routeKindImagePools.city;
  const image = pool[globalIndex % pool.length];
  return image || provinceFallbackImages[province] || '/assets/spots/chengdu-taikooli-ai.jpg';
}

function getRouteKind(city, province, cityIndex, routeProfile) {
  if (routeProfile.kind) return routeProfile.kind;
  const baseKind = getCityKind(city, province, cityIndex + (routeProfile.kindOffset || 0));
  if (routeProfile.suffix === '经典地标线' && baseKind === 'oldtown') return 'palace';
  return baseKind;
}

function makeCityCoverageSpot(province, city, cityIndex, globalIndex, routeProfile) {
  const kind = getRouteKind(city, province, cityIndex, routeProfile);
  const coords = cityCoordinates[city] || [30 + (globalIndex % 12), 104 + (globalIndex % 18)];
  const image = pickRouteImage(province, city, kind, globalIndex, routeProfile);
  const archivePrefix = province.slice(0, 2).toUpperCase();
  const name = `${city}${routeProfile.suffix}`;
  const routeTags = routeProfile.tags.concat(kindThemeTags[kind] || []);
  const routeLocation = typeof routeProfile.location === 'function' ? routeProfile.location(city, province) : `${city}${routeProfile.location}`;
  return {
    id: 1001 + globalIndex,
    name,
    city,
    province,
    location: routeLocation,
    lat: coords[0],
    lng: coords[1],
    score: 4.4 + ((globalIndex % 5) * 0.1),
    badge: routeProfile.badge,
    archiveNo: `${archivePrefix}-${String(globalIndex + 1).padStart(3, '0')}`,
    bestTime: kind === 'citywalk' ? '10:00-12:00、15:30-18:00' : (kind === 'city' ? '傍晚蓝调时刻、亮灯后 30 分钟' : (kind === 'water' ? '清晨、日落前 1 小时' : '上午柔光、日落前')),
    summary: routeProfile.summary(city, province),
    aiExampleImage: image,
    aiExampleLabel: `拍摄参考 · ${city}`,
    aiExamplePrompt: routeProfile.prompt(city),
    palette: kind === 'citywalk' ? ['#eadcc8', '#4f6258', '#c28b55'] : (kind === 'city' ? ['#e4d7c5', '#304154', '#d2a05b'] : (kind === 'water' ? ['#dbe8e4', '#557f8c', '#d8bd8d'] : ['#e3d2b6', '#6c5b43', '#839078'])),
    tags: [province, city, routeProfile.badge, kind].concat(routeTags),
    themeTags: [routeProfile.badge].concat(routeTags).slice(0, 4),
    locations: buildLocations(kind, name, city),
    tips: [
      kind === 'citywalk' ? '路线建议控制在 2-4 公里，先确认起点和终点，避免临时绕太远。' : '出发前建议确认具体景区开放时间、预约规则和末班交通。',
      kind === 'citywalk' ? '每段只选 1-2 个画面重点：路牌、街角、树影、店招、河岸或终点地标。' : '如果时间有限，优先选同一区域内 2-3 个点串联，避免跨城奔波。',
      kind === 'citywalk' ? '拍摄顺序按“开场环境-中段行走-终点封面”排，整组照片更像完整路线。' : '到达后先拍一张环境照，再补人像和细节，整组内容会更像真实游记。'
    ],
    composition: [
      kind === 'citywalk' ? '起点照要带路牌或街口，先告诉用户“从这里开始”。' : '线路类内容先保留地标或街区主体，人物小比例进入画面。',
      kind === 'citywalk' ? '中段用转角、树影、店招和道路延伸线做连续感。' : '用道路、水岸、桥梁、台阶或建筑线条做视觉引导。',
      kind === 'citywalk' ? '终点照用地标、河岸、公园或天际线收尾，适合作为封面。' : '同一城市可按远景、人像、细节三类各拍一组。'
    ]
  };
}

const spotData = spotBlueprints.map(makeSpotFromBlueprint).concat(
  provinceCityGroups.reduce((list, [province, cities]) => {
    cities.forEach((city, cityIndex) => {
      cityRouteProfiles.forEach((routeProfile) => {
        list.push(makeCityCoverageSpot(province, city, cityIndex, list.length, routeProfile));
      });
    });
    return list;
  }, [])
);

